var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아직 버틸 수 있어…… 아니, 버텨야 해!","JPN":"まだ耐えられる……いや、耐えないと！","ENG":"I can still keep fighting… No, I must!","TWN":"我還撐得下去……不，是一定要撐下去！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 쓰러지면…… 선배가……","JPN":"私が倒れたら……先輩が……","ENG":"If I fall… Shiyoon's in danger…","TWN":"我倒下去的話……那前輩他……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭, 제기랄……!","JPN":"く、くそ……！","ENG":"Hngh... Damn it!","TWN":"唔！可惡……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"역시, 무리해서 일깨운 용혈의 힘은 이 정도군요.","JPN":"やはり、無理して目覚めさせた龍血の力ではこの程度ですね。","ENG":"Alas, so this is the extent of the power forcibly drawn from the Dragon Blood.","TWN":"果然，勉強喚醒的龍血力量就只有這樣。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아직 자신이 무엇인지도 모르는 어린 늑대한테조차 고전하다니.","JPN":"まだ自分が何者かも気づいていない幼い狼に苦戦するなんて。","ENG":"He struggles against a mere Wolf pup who doesn't even know what she is.","TWN":"對手不過是個連自己是誰都還搞不清楚地幼狼，這樣也陷入苦戰。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"당신…… 설마 일부러 숨어 있다가 나타난 건가요?","JPN":"あなたは……もしかしてわざと隠れていたんですか？","ENG":"Were you hiding all this time?","TWN":"你……該不會是故意躲起來的吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양을 쓰러트리고 싶다면 어째서 구경만 하는 거죠? 지금이 적기 아닌가요?","JPN":"ミナさんを倒したいならどうして何もしないんですか？　今が好機なのでは？","ENG":"Why are you just watching if you want to take down Mina? Wouldn't this be the perfect time to strike?","TWN":"你不是想打倒米娜嗎？怎麼可以只在旁邊偷看呢？現在不是好機會嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"말했을 텐데요. 이건 용의 탄생을 위해 제물을 바치는 <color=#ffd34c>의식</color>입니다.","JPN":"言ったはずです。これは龍の誕生のために生贄を捧げる<color=#ffd34c>儀式</color>です。","ENG":"Like I said... This is simply a <color=#ffd34c>ritual</color> to offer a sacrifice for the birth of the Dragon.","TWN":"我剛不是說過，獻祭<color=#ffd34c>儀式</color>目的，是要讓龍能夠誕生。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제 손으로 저 늑대를 죽여 봐야 아무런 의미도 없지요.","JPN":"私の手であの狼を殺しても何の意味もありません。","ENG":"Killing the Wolf myself will do no good.","TWN":"那隻狼是不是我親手殺的根本沒差。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러면 그것과…… 저 괴물의 목소리가…… 무슨 관련이 있는 거죠?","JPN":"じゃあアレと……あの化け物の声が……何の関係があるのですか？","ENG":"Then… what's that monster's voice got to do with anything?","TWN":"這麼說來……這和剛才那怪物的聲音……有什麼關聯囉？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저런. 부모님의 목소리를 듣고 놀라셨나 보군요. 이방인이여.","JPN":"ああ、両親の声を聞いて驚いたようですね、異邦人よ。","ENG":"Ah. The voice of your parents must have startled you, outsider.","TWN":"哎呀～剛剛聽到父母親的聲音嚇一跳嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용혈의 계승자는 번뇌에서 벗어날 수 없습니다.","JPN":"龍血の継承者は煩悩から逃れられません。","ENG":"The heir to the Dragon Blood cannot escape their Kleshas.","TWN":"龍血的繼承者無法脫離煩惱，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 번뇌라는 것은 삶의 끝을 지나, 죽음 이후에도 헤어날 수 없는 저주죠.","JPN":"そして煩悩というものは人生の果てを過ぎ、死を迎えても抜け出せない呪いです。","ENG":"Kleshas are a curse that extends beyond a single lifetime, beyond death itself.","TWN":"而且就算你走到人生的盡頭，死去後也無法擺脫。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"설마……","JPN":"まさか……","ENG":"You mean…","TWN":"難道……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용혈의 힘은 대를 이어갈수록 강해집니다.","JPN":"龍血の力は世代を継ぐことで強くなります。","ENG":"The power of the Dragon Blood grows more potent with each generation.","TWN":"龍血的力量越是傳承下去就會越強大。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 이 세상에…… 대가가 없는 힘은 없습니다.","JPN":"そしてこの世に……代償のない力はありません。","ENG":"And in this world… there is no power without a price.","TWN":"而且在這個世界上……所有的力量都是需要付代價的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말도 안 돼…….","JPN":"そんな……","ENG":"Impossible…","TWN":"胡說……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"웃기지 마! 그런 말도 안 되는 일이 있을 리가……!","JPN":"ふざけるな！　そんなことあり得ない……！","ENG":"You think I'll fall for that?! That's impossible!","TWN":"胡說八道！怎麼可能有這麼荒謬的事……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"부정하셔도 소용없습니다.","JPN":"否定しても無駄です。","ENG":"There is no use in denial.","TWN":"你不想承認也沒辦法。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신의 부모도, 그리고 그 부모의 부모도, 최초의 구도자로부터 이어져 내려온 후손들 전부.","JPN":"あなたの親も、そしてその親の親も、始まりの求道者から受け継がれてきた子孫全員。","ENG":"It is the same for your parents, their parents, and all the descendents of the Seeker.","TWN":"從求道者開始，包括你的父母，還有你父母的父母，所有的後裔，"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 모든 자들의 영혼은 저 용의 피라는 연옥 속에 묶여 담금질 당하고 있는 겁니다.","JPN":"そのすべての者の魂は、あの龍の血という煉獄の中で焼かれ続けているのです。","ENG":"All of their souls are being forged in the crucible of Dragon Blood, forever fettered to that purgatory.","TWN":"他們的靈魂全都在名為龍血的煉獄中受盡折磨，"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"억겁의 시간 너머, 기약조차 없는 바라밀의 순간까지.","JPN":"億劫の先、何時になるかもわからない波羅蜜の瞬間まで。","ENG":"Beyond endless time itself, until that eternally distant moment of Paramita.","TWN":"直到解脫達到彼岸，波羅蜜圓滿時為止。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아직도 저 용인을 괴물이라고 부를 수 있나요?","JPN":"まだあの龍人を化け物と呼べますか？","ENG":"Do you still dare call that Dragonoid a monster?","TWN":"你還認為那個龍人是怪物嗎？"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이라면 알아차렸겠죠.","JPN":"あなたなら気づいたでしょう。","ENG":"You must realize the truth by now.","TWN":"你應該看得出來，"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"방금 당신을 부른 건 가짜도 흉내도 아닌 진짜 당신 어머니의 목소리였다는 것을.","JPN":"さっきあなたを呼んだのは、偽物でも真似でもない本物のあなたの母親の声だったことを。","ENG":"The voice you just heard was no imposter's… but the true voice of your mother.","TWN":"剛才和你說話的聲音，不是假象，也不是偽裝的，真的是你母親的聲音。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자, 선물로 이걸 드리죠.","JPN":"さあ、贈り物です。","ENG":"Now, let me give you a little gift.","TWN":"這個送你當作禮物吧。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"Isn't this…","TWN":"這是……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"권총입니다.","JPN":"拳銃です。","ENG":"A pistol.","TWN":"是槍。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 땅의 이방인들이 쓰는 품위 없는 무기들 중의 하나지요.","JPN":"この地の異邦人たちが使う品のない武器の一つです。","ENG":"One of those unsophisticated weapons wielded by outsiders to this land.","TWN":"是這塊土地上的外邦人使用的平凡武器之一。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이걸……. 왜…….","JPN":"これを……なぜ……","ENG":"Why… would you give this to me?","TWN":"給我這個……要幹嘛……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용혈을 거의 다 빼앗긴 당신에게 카운터의 힘은 남아있지 않을 겁니다.","JPN":"龍血をほとんど奪われたあなたにカウンターの力は残っていません。","ENG":"With your Dragon Blood nearly depleted, so must your powers as a Counter be.","TWN":"你身上的龍血已經被奪走大部分，制裁者的力量應該也不復在。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 당신이 사용할 수 있는 무기는 이런 평범한 것들뿐이니까요.","JPN":"そんなあなたが使用できる武器はこんな平凡な物しかありません。","ENG":"In your current state, you can only wield ordinary weapons such as this.","TWN":"現在的你，能夠使用的就只有這種平凡的武器。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러니까…… 제가 왜 무기가 필요한 거죠……?","JPN":"だから……なぜ僕に武器が必要なんですか……？","ENG":"So… why do I need a weapon?","TWN":"我就問……我要武器幹嘛？"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그걸로 저 늑대를 쏘세요.","JPN":"それであの狼を撃ってください。","ENG":"Shoot the Wolf with it.","TWN":"拿這把槍射那隻狼。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러면 당신과 당신 부모의 구원은 이루어집니다.","JPN":"そうすればあなたとあなたの親は救われるでしょう。","ENG":"Then salvation shall be granted to you and your parents.","TWN":"如此才能成就你和你父母的救贖。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무슨 바보 같은 농담을…….","JPN":"なにをバカなことを……","ENG":"That's the dumbest load of bull I've ever heard…","TWN":"你在胡言亂語什麼……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"애초에 쏠 이유도 없지만, 미나 양은 강력한 카운터입니다.","JPN":"そもそも撃つ理由もありませんが、ミナさんは強力なカウンターです。","ENG":"I'd never shoot her in the first place, but Mina is a powerful Counter.","TWN":"我根本就沒有開槍的理由，更何況米娜是個很有能力的制裁者。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"고작 권총탄을 맞는다고……. 아파할 것 같진 않은데요.","JPN":"平凡な銃に撃たれたとしても……痛くも痒くもないはず。","ENG":"Even if she got shot with this pistol… It'll barely tickle her.","TWN":"區區一把槍……就算打到她也不會痛吧！"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"물론 그렇겠지요.","JPN":"もちろんそうでしょう。","ENG":"Indeed.","TWN":"這我當然知道。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이건 당신의 <color=#ffd34c>의지</color>를 증명할 도구입니다.","JPN":"これはあなたの<color=#ffd34c>意志</color>を証明する道具です。","ENG":"But this is a tool to prove your <color=#ffd34c>resolve</color>.","TWN":"拿槍射她的重點在於表達你的<color=#ffd34c>意志</color>。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신의 몸에서 분리하긴 했지만 저 용인은 결국 당신의 피로 만들어진 존재.","JPN":"あなたの体から分離したとはいえ、あの龍人はあなたの血で作られた存在。","ENG":"Although that Dragonoid was separated from your body, it is still created from your blood.","TWN":"那個龍人雖然是從你身上分離出來的，但他畢竟用你的血所造的。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 불완전한 용인이 진정한 용으로 우화하려면 당신의 의지가 필요합니다.","JPN":"そんな不完全な龍人が真の龍に羽化するためには、あなたの意志が必要です。","ENG":"In order for such an incomplete being to transmute to a true Dragon, your resolve is needed.","TWN":"他要從不完整的狀態成為真正的龍，就需要你的意志。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 저 늑대를 겨누고 방아쇠를 당긴다면……","JPN":"あなたがあの狼を狙って引き金を引くなら……","ENG":"If you point the gun at the Wolf and pull the trigger…","TWN":"只要你瞄準那隻狼扣下板機……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그건 당신이 제물을 받아들이겠다는 의지의 증명이 되겠지요.","JPN":"それはあなたが生贄を受け入れるという意志の証明になるでしょう。","ENG":"It would demonstrate your resolve to accept this sacrifice.","TWN":"就足以證明你接受這個祭物的意志。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……아직도 망설이는 건가요?","JPN":"……まだ迷っているのですか？","ENG":"…Do you still hesitate?","TWN":"……你還在猶豫不決嗎？"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"불쌍한 사람이로군요.","JPN":"哀れな人ですね。","ENG":"Alas, you poor soul.","TWN":"真是可憐。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전에도 말했듯이 당신은 소심하고 내성적인 사람입니다.","JPN":"前にも言いましたが、あなたは小心者で内気な人間です。","ENG":"Like I said, you are a timid introvert.","TWN":"我之前也說過，你其實是個膽小又內向的人。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"가면을 쓰고 있다는 건, 보통 자신을 받아들이지 못한다는 뜻이지요.","JPN":"仮面を被るということは、普段の自分を受け入れられないという意味でしょう。","ENG":"People wear masks when they cannot accept who they truly are.","TWN":"會戴上面具示人，通常就表示無法接受真實的自己。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은 타인에 의해 부모를 잃었고, 선조는 운명에 저주를 남겼습니다.","JPN":"あなたは他人によって両親を失い、先祖は運命に呪いを遺しました。","ENG":"You lost your parents at the hands of another, while your ancestors have left you with a cursed fate.","TWN":"你因為其他人而失去父母，祖先又留下命運的詛咒。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런데 어째서 분노하지 않는 거죠? 정말로 이 모든 일을 받아들일 만 합니까?","JPN":"なのになぜ怒らないんですか？　本当にすべてを素直に受け入れているのですか？","ENG":"Why, then, do you not burn in rage? Can you truly accept all of this?","TWN":"為什麼你完全不生氣呢？難道這些事你真的都可以接受嗎？"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그건 이상해요.","JPN":"それはありえません。","ENG":"How peculiar.","TWN":"完全無法理解。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"누구에게 물어도 이상하다고 할 겁니다.","JPN":"誰に聞いてもおかしいと言うでしょう。","ENG":"Anyone would find this to be very odd indeed.","TWN":"不管任何人都無法理解吧？"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은 그 불쌍한 구도자처럼 당신이 겪은 비극에 대해 지금까지 스스로에게 복수하며 살아온 겁니다.","JPN":"あなたはあの哀れな求道者のように、\\n自分が経験した悲劇に対して今まで自分自身に復讐しながら生きてきたのです。","ENG":"Like that poor Seeker, you've made yourself the object of your own revenge for the tragedies you suffered.","TWN":"你和求道者一樣，對於自己所經歷的悲劇，完全沒有積極的作為，而是把自己當作報仇的對象。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이젠 자신의 진정한 분노와 욕망에 솔직해질 때입니다.","JPN":"今が自分の真の怒りと欲望に正直になる時です。","ENG":"It is now time for you to honestly recognize your rage and desire.","TWN":"但現在是時候誠實面對自己真正的憤怒和慾望了。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"언제까지나 부모 잃은 꼬마인 채로 멈춰있을 수는 없어요.","JPN":"いつまでも親を無くした子どものまま、止まっているわけにはいきません。","ENG":"You cannot remain an orphan child forever.","TWN":"不能一直把自己看作是當年那個失去父母的小孩，"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"원하든 원치 않든, 어른이 되려면 현실을 인정하고 전진해야 합니다.","JPN":"望んでも望まなくても、大人になるためには現実を認めて前に進まなければ。","ENG":"Whether you want it or not, you must recognize reality and move on in order to become an adult.","TWN":"不管你願不願意，都必須要認清現實繼續往前走才能成為大人。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 현실이 자신의 생각과 다르다고 하더라도.","JPN":"たとえその現実が自分の考えと違っていたとしても。","ENG":"Even if that reality is not what you'd prefer.","TWN":"就算現實與你所以為的有落差。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"만약…… 만약 제가 미나 양을 쏜다면, 어떻게 되죠?","JPN":"もし……もし僕がミナさんを撃つとどうなるんですか？","ENG":"If… I shoot Mina, what's going to happen?","TWN":"如果……我真的開槍射米娜，會發生什麼事？"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저 용인은 당신의 의지에 따라 제물을 잡아먹고 진정한 용이 되겠지요.","JPN":"あの龍人はあなたの意志により、生贄を食らい真の龍となるでしょう。","ENG":"That Dragonoid will devour the sacrifice according to your will and become the true Dragon.","TWN":"龍人就會按照你的意志吃掉祭物後成為真正的龍。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 진정한 용은 인세의 번뇌를 초월한 존재.","JPN":"そして真の龍は人世の煩悩を超えた存在。","ENG":"A true Dragon is a being that has transcended the Kleshas of mortality.","TWN":"而且真正的龍是超脫人世間的煩惱的。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"망령이 되어 고통 받던 영혼들도 용의 일부가 되어 다시 태어나게 될 겁니다.","JPN":"亡霊となり苦しんでいた魂も、龍の一部にとなって生まれ変わることになるでしょう。","ENG":"Even the lost souls that suffered in death will rise again as part of the Dragon.","TWN":"受苦的靈魂也會成為龍的一部分後重生。"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"부활의 지팡이를 이어받은 자의 이름을 걸고 약속하지요.","JPN":"復活の杖を受け継いだ者の名にかけて約束します。","ENG":"I swear upon my title as the successor of the Staff of Resurrection that this is the truth.","TWN":"我以復活之杖繼承者之名跟你保證！"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"MAINSTREAM_7080010","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서, 선배! 더 이상…… 버티기 힘들어……","JPN":"せ、先輩！　これ以上は……耐えられない……","ENG":"S-Shiyoon! I don't think… I can take this much longer!","TWN":"前…前輩！我……我快撐不下去了……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아직 내가 막을 수 있는 동안…… 도망쳐! 어떻게든……!!","JPN":"まだ私が止めている間に……逃げて！　なんとしても……！！","ENG":"Run… While I can still keep this thing away… Run, damn it!","TWN":"趁我還撐得住的時候……你趕快逃！快走……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양…….","JPN":"ミナさん……","ENG":"Mina…","TWN":"米娜……"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……미안해요.","JPN":"……ごめんなさい。","ENG":"…I'm sorry.","TWN":"對不起……"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};